defmodule MyApp.ProductController do
  use MyApp.Web, :controller

  def search(conn, params) do
    allowed_sort_columns = ["name", "price"]
    allowed_comparison_operators = [">", "<"]

    query = from(p in Product,
      order_by: ^params["sort"] |> Enum.at(0),
      where: fragment("name LIKE ?", ^"%#{params["search"]}%" )
    )

    case params["operator"] do
      ">" -> 
        query = from(p in query, where: p.price > ^params["value"])
      "<" ->
        query = from(p in query, where: p.price < ^params["value"])
    end

    products = Repo.all(query)
    render conn, "index.html", products: products
  end
